&lt;p&gt;&lt;span data-contrast=&quot;auto&quot;&gt;&lt;span style=&quot;text-decoration: underline;&quot;&gt;&lt;strong&gt;Responsibilities&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
